    // ========== ACCESS MODIFIERS & ENCAPSULATION ==========
    public class BankAccount
    {
        // Private field — chỉ truy cập trong class này
        private decimal _balance;

        // Public property — giao diện truy cập từ bên ngoài
        public string AccountNumber { get; private set; }

        // Property với validation trong setter
        public decimal Balance
        {
            get => _balance;
            private set
            {
                if (value < 0)
                    throw new ArgumentException("Số dư không thể âm.");
                _balance = value;
            }
        }

        // Constructor khởi tạo tài khoản
        public BankAccount(string accountNumber, decimal initialBalance)
        {
            AccountNumber = accountNumber ?? throw new ArgumentNullException(nameof(accountNumber));
            Balance = initialBalance;          // Validation được gọi qua property setter
        }

        // Public method — giao diện thao tác với tài khoản
        public void Deposit(decimal amount)
        {
            if (amount <= 0)
                throw new ArgumentException("Số tiền gửi phải lớn hơn 0.");
            Balance += amount;
        }

        public bool Withdraw(decimal amount)
        {
            if (amount <= 0)
                throw new ArgumentException("Số tiền rút phải lớn hơn 0.");
            if (amount > Balance)
            {
                Console.WriteLine("  Số dư không đủ.");
                return false;
            }
            Balance -= amount;
            return true;
        }
    }

    // ========== INHERITANCE ==========
    // public: kế thừa được, internal: cùng assembly
    public class Animal
    {
        public string Name { get; set; }
        public int Age { get; set; }

        // Virtual method — cho phép class con ghi đè
        public virtual void Speak()
        {
            Console.WriteLine($"{Name} đang phát ra âm thanh.");
        }

        // Constructor của class cha
        public Animal(string name, int age)
        {
            Name = name;
            Age = age;
        }

        // Virtual destructor pattern (IDisposable)
        public virtual void Dispose()
        {
            Console.WriteLine($"{Name} đang được giải phóng.");
        }
    }

    // Dog kế thừa từ Animal — quan hệ IS-A: Dog IS An Animal
    public class Dog : Animal
    {
        public string Breed { get; set; }       // Property riêng của Dog

        // Gọi constructor cha bằng base()
