    // ========== GENERICS — GENERIC CLASS ==========
    // Generic class với constraint: T phải là class, có default constructor
    public class DataStore<T> where T : class, new()
    {
        private readonly List<T> _items = new List<T>();

        public void Add(T item) => _items.Add(item);

        public T Get(int index) =>
            index >= 0 && index < _items.Count ? _items[index] : default;

        public List<T> GetAll() => new List<T>(_items);

        public int Count => _items.Count;
    }

    // Generic class với constraint T phải implement IComparable
    public class SortedList<T> where T : IComparable<T>
    {
        private readonly List<T> _items = new List<T>();

        public void Add(T item)
        {
            _items.Add(item);
            _items.Sort();                        // IComparable cho phép so sánh
        }

        public T this[int index] => _items[index];

        public int Count => _items.Count;
    }

    // Generic Method — hoạt động độc lập với class chứa nó
    public static class ArrayHelper
    {
        // Swap hai phần tử bất kỳ kiểu gì (constraint: class để dùng ref)
        public static void Swap<T>(ref T a, ref T b) where T : class
        {
            T temp = a;
            a = b;
            b = temp;
        }

        // Tìm phần tử lớn nhất trong mảng
        public static T Max<T>(params T[] items) where T : IComparable<T>
        {
            if (items == null || items.Length == 0)
                throw new ArgumentException("Mảng không được rỗng.");

            T max = items[0];
            for (int i = 1; i < items.Length; i++)
                if (items[i].CompareTo(max) > 0)
                    max = items[i];
            return max;
        }

        // Filter collection bằng predicate
        public static IEnumerable<T> Filter<T>(IEnumerable<T> source, Func<T, bool> predicate)
        {
            foreach (T item in source)
                if (predicate(item))
                    yield return item;           // Yield trả về từng phần tử một
        }
    }

