    // Event arguments nên inherit từ EventArgs
    public class VideoEventArgs : EventArgs
    {
        public Video Video { get; }
        public DateTime ProcessedAt { get; }

        public VideoEventArgs(Video video)
        {
            Video = video;
            ProcessedAt = DateTime.Now;
        }
    }

    public class VideoEncoder
    {
        // Event dùng EventHandler<T> thay vì custom delegate (chuẩn .NET)
        public event EventHandler<VideoEventArgs> VideoEncoded;

        // Phương thức raise event — protected virtual để subclass override
        protected virtual void OnVideoEncoded(Video video)
        {
            VideoEncoded?.Invoke(this, new VideoEventArgs(video));
        }

        public void Encode(Video video)
        {
            Console.WriteLine($"  Mã hóa video: {video.Title} ({video.Duration}s)...");
            System.Threading.Thread.Sleep(100);  // Giả lập xử lý

            // Thông báo cho tất cả subscribers
            OnVideoEncoded(video);
        }
    }

