using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Net.Http;
using System.Text.Json;
using System.Threading;
using System.Threading.Tasks;

namespace CSharpAsyncAwait
{
    public class Post
    {
        public int Id { get; set; }
        public string Title { get; set; }
        public string Body { get; set; }
    }

    public class AsyncService
    {
        private readonly HttpClient _httpClient;

        public AsyncService()
        {
            _httpClient = new HttpClient();        // HttpClient implement IDisposable
        }

        // ========== ASYNC METHOD — TƯƠNG ĐƯƠNG ĐỒNG BỘ ==========

        // Synchronous version (blocking — KHÔNG NÊN dùng cho I/O)
        public string ReadFileSync(string path)
        {
            return File.ReadAllText(path);         // Blocking thread cho đến khi đọc xong
        }

        // Async version — trả về Task<string>, giải phóng thread
        public async Task<string> ReadFileAsync(string path)
        {
            // await giải phóng luồng trong khi I/O đang diễn ra
            return await File.ReadAllTextAsync(path);
        }

        // Async với CancellationToken — cho phép hủy operation
        public async Task<string> FetchDataWithCancel(string url, CancellationToken ct)
        {
            // CancellationToken kiểm tra trạng thái hủy tại các điểm có thể hủy
            var response = await _httpClient.GetAsync(url, ct);
            response.EnsureSuccessStatusCode();     // Ném exception nếu HTTP không thành công
            return await response.Content.ReadAsStringAsync(ct);
        }

        // Async với timeout
        public async Task<string> FetchWithTimeout(string url, int timeoutMs = 5000)
        {
            using var cts = new CancellationTokenSource(timeoutMs);
            try
            {
                return await FetchDataWithCancel(url, cts.Token);
            }
            catch (TaskCanceledException)
            {
                throw new TimeoutException($"Yêu cầu vượt quá {timeoutMs}ms");
            }
        }

        // ========== CHẠY NHIỀU TASKS ĐỒNG THỜI ==========

        // Task.WhenAll — chờ tất cả tasks hoàn thành
        public async Task<List<Post>> FetchAllPostsAsync(string[] urls)
        {
            // Tạo danh sách tasks, mỗi task gọi một URL
            var tasks = new List<Task<Post>>();
            foreach (var url in urls)
            {
                tasks.Add(FetchPostAsync(url));
            }

            // WhenAll chờ tất cả đồng thời (parallel), không tuần tự
            Post[] results = await Task.WhenAll(tasks);
            return new List<Post>(results);
        }

        // Task.WhenAny — hoàn thành khi task đầu tiên xong
        public async Task<Post> FetchFirstAvailable(string[] urls)
        {
            var tasks = urls.Select(url => FetchPostAsync(url)).ToList();
            while (tasks.Count > 0)
            {
                // WaitAny trả về index của task hoàn thành đầu tiên
                Task<Post> completed = await Task.WhenAny(tasks);
                tasks.Remove(completed);
                try
                {
                    return await completed;       // Lấy kết quả
                }
                catch
                {
                    // Task bị lỗi, thử task tiếp theo
                    continue;
                }
            }
            throw new InvalidOperationException("Tất cả requests đều thất bại.");
        }

        // Gọi HTTP và deserialize JSON
        private async Task<Post> FetchPostAsync(string url)
        {
            var response = await _httpClient.GetAsync(url);
            response.EnsureSuccessStatusCode();
            var json = await response.Content.ReadAsStringAsync();
            return JsonSerializer.Deserialize<Post>(json);
        }

        // ========== SEMAPHORE SLIM — GIỚI HẠN CONCURRENCY ==========
        private static readonly SemaphoreSlim _semaphore = new SemaphoreSlim(3); // Tối đa 3 concurrent

        public async Task ProcessWithLimitAsync(List<string> items)
        {
            var tasks = items.Select(async item =>
            {
                await _semaphore.WaitAsync();       // Chờ nếu đã đạt giới hạn
