    // Rate Limiting Middleware — giới hạn requests per client
    public class RateLimitingMiddleware
    {
        private readonly RequestDelegate _next;
        private readonly Dictionary<string, int> _requestCounts = new();
        private readonly object _lock = new();
        private const int MaxRequests = 100;
        private const int WindowSeconds = 60;

        public RateLimitingMiddleware(RequestDelegate next)
        {
            _next = next;
        }

        public async Task InvokeAsync(HttpContext context)
        {
            var clientId = context.Connection.RemoteIpAddress?.ToString() ?? "unknown";

            lock (_lock)
            {
                var now = DateTime.UtcNow;
                if (!_requestCounts.ContainsKey(clientId))
                    _requestCounts[clientId] = 0;

                _requestCounts[clientId]++;
                if (_requestCounts[clientId] > MaxRequests)
                {
                    context.Response.StatusCode = 429;
                    context.Response.Headers["Retry-After"] = WindowSeconds.ToString();
                    await context.Response.WriteAsJsonAsync(new
                    {
                        error = "Too Many Requests",
                        retryAfter = WindowSeconds
                    });
                    return; // Short-circuit
                }
            }

            await _next(context); // Continue pipeline
        }
    }

    // Correlation ID Middleware — thêm request tracking ID
    public class CorrelationIdMiddleware
    {
        private readonly RequestDelegate _next;
        private const string CorrelationIdHeader = "X-Correlation-ID";

        public CorrelationIdMiddleware(RequestDelegate next) => _next = next;

        public async Task InvokeAsync(HttpContext context)
        {
            // Lấy hoặc tạo mới correlation ID
            if (!context.Request.Headers.TryGetValue(CorrelationIdHeader, out var correlationId))
                correlationId = Guid.NewGuid().ToString();

            // Lưu vào Items để dùng ở mọi nơi trong request
            context.Items["CorrelationId"] = correlationId.ToString();
            context.Response.Headers[CorrelationIdHeader] = correlationId;

            // Ghi vào log context
            using (Serilog.Context.LogContext.PushProperty("CorrelationId", correlationId))
            {
                await _next(context);
            }
        }
    }

