    // ============================================================================
    // JWT SERVICE — GENERATE & VALIDATE TOKENS
    // ============================================================================
    public class JwtService
    {
        private readonly JwtSettings _settings;

        public JwtService(JwtSettings settings)
        {
            _settings = settings;
        }

        public AuthResponse GenerateTokens(UserInfo user)
        {
            // Access Token — sống ngắn (15 phút)
            var accessToken = GenerateAccessToken(user);
            // Refresh Token — sống dài (7 ngày)
            var refreshToken = GenerateRefreshToken();

            return new AuthResponse
            {
                Token = accessToken,
                RefreshToken = refreshToken,
                ExpiresAt = DateTime.UtcNow.AddMinutes(_settings.AccessTokenExpirationMinutes),
                User = user
            };
        }

        public string GenerateAccessToken(UserInfo user)
        {
            var securityKey = new SymmetricSecurityKey(
                Encoding.UTF8.GetBytes(_settings.SecretKey));
            var credentials = new SigningCredentials(
                securityKey, SecurityAlgorithms.HmacSha256);

            // Claims — thông tin user trong token
            var claims = new List<Claim>
            {
                new Claim(JwtRegisteredClaimNames.Sub, user.Id.ToString()),
                new Claim(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString()), // JWT ID
                new Claim(JwtRegisteredClaimNames.Iat,
                    DateTimeOffset.UtcNow.ToUnixTimeSeconds().ToString(),
                    ClaimValueTypes.Integer64),
                new Claim("username", user.Username),
                new Claim("email", user.Email)
            };

            // Thêm roles vào claims
            foreach (var role in user.Roles)
                claims.Add(new Claim(ClaimTypes.Role, role));

            // Claims tùy chỉnh
            claims.Add(new Claim("department", "Engineering"));

            var token = new JwtSecurityToken(
                issuer: _settings.Issuer,
                audience: _settings.Audience,
                claims: claims,
                expires: DateTime.UtcNow.AddMinutes(_settings.AccessTokenExpirationMinutes),
                signingCredentials: credentials);

            return new JwtSecurityTokenHandler().WriteToken(token);
        }

        public ClaimsPrincipal? ValidateToken(string token)
        {
            var tokenHandler = new JwtSecurityTokenHandler();
            var key = Encoding.UTF8.GetBytes(_settings.SecretKey);

            try
            {
                var principal = tokenHandler.ValidateToken(token, new TokenValidationParameters
                {
                    ValidateIssuerSigningKey = true,
                    IssuerSigningKey = new SymmetricSecurityKey(key),
                    ValidateIssuer = true,
                    ValidIssuer = _settings.Issuer,
                    ValidateAudience = True,
                    ValidAudience = _settings.Audience,
                    ValidateLifetime = true,           // Kiểm tra expiration
                    ClockSkew = TimeSpan.Zero           // Không cho phép thời gian lệch
                }, out _);
                return principal;
            }
            catch
            {
                return null; // Token không hợp lệ
            }
        }

        public string GenerateRefreshToken()
        {
            var randomBytes = new byte[64];
            using var rng = RandomNumberGenerator.Create();
            rng.GetBytes(randomBytes);
            return Convert.ToBase64String(randomBytes);
        }
    }

