namespace CachingAndBackgroundJobs
{
    // ============================================================================
    // IN-MEMORY CACHING
    // ============================================================================
    public class InMemoryCacheService
    {
        private readonly IMemoryCache _cache;
        private static readonly TimeSpan DefaultExpiration = TimeSpan.FromMinutes(10);

        public InMemoryCacheService(IMemoryCache cache)
        {
            _cache = cache;
        }

        public T? GetOrSet<T>(string key, Func<T?> factory, TimeSpan? expiration = null)
        {
            if (_cache.TryGetValue(key, out T? value))
            {
                Console.WriteLine($"[Cache] HIT: {key}");
                return value;
            }

            Console.WriteLine($"[Cache] MISS: {key}");
            value = factory();
            if (value != null)
            {
                var options = new MemoryCacheEntryOptions
                {
                    AbsoluteExpirationRelativeToNow = expiration ?? DefaultExpiration,
                    SlidingExpiration = TimeSpan.FromMinutes(5),
                    Size = 1,                         // Size limit
                    Priority = CacheItemPriority.Normal
                };
                _cache.Set(key, value, options);
            }
            return value;
        }

        public void Remove(string key) => _cache.Remove(key);

        public bool Exists(string key) => _cache.TryGetValue(key, out _);
    }

    // ============================================================================
    // REDIS DISTRIBUTED CACHING
    // ============================================================================
    public class RedisCacheService
    {
        private readonly IDatabase _db;
        private readonly IConnectionMultiplexer _redis;
        private static readonly TimeSpan DefaultExpiration = TimeSpan.FromMinutes(15);

        public RedisCacheService(IConnectionMultiplexer redis)
        {
            _redis = redis;
            _db = redis.GetDatabase();
        }

        public async Task<T?> GetAsync<T>(string key) where T : class
        {
            var value = await _db.StringGetAsync(key);
            if (value.IsNull)
            {
                Console.WriteLine($"[Redis] MISS: {key}");
                return null;
            }
            Console.WriteLine($"[Redis] HIT: {key}");
            return System.Text.Json.JsonSerializer.Deserialize<T>(value!);
        }

        public async Task SetAsync<T>(string key, T value, TimeSpan? expiration = null) where T : class
        {
            var json = System.Text.Json.JsonSerializer.Serialize(value);
            await _db.StringSetAsync(key, json, expiration ?? DefaultExpiration);
            Console.WriteLine($"[Redis] SET: {key} (expires in {expiration?.TotalMinutes ?? DefaultExpiration.TotalMinutes} min)");
        }

        public async Task RemoveAsync(string key)
        {
            await _db.KeyDeleteAsync(key);
            Console.WriteLine($"[Redis] DELETE: {key}");
        }

        public async Task<bool> ExistsAsync(string key) => await _db.KeyExistsAsync(key);

        // ===== CACHE-ASIDE PATTERN =====
        public async Task<List<Product>> GetProductsAsync(int categoryId)
        {
            var cacheKey = $"products:category:{categoryId}";

            // Try cache first
            var cached = await GetAsync<List<Product>>(cacheKey);
            if (cached != null) return cached;

            // Cache miss — load from DB (simulated)
            var products = await LoadProductsFromDb(categoryId);

            // Store in cache
            await SetAsync(cacheKey, products, TimeSpan.FromMinutes(10));
            return products;
        }

        private Task<List<Product>> LoadProductsFromDb(int categoryId)
        {
            Console.WriteLine($"[DB] Loading products for category {categoryId}");
            return Task.FromResult(new List<Product>
