    public class CursorPaginationService
    {
        public record Product(string Id, string Name, DateTime CreatedAt, decimal Price);

        public CursorPagedResult<Product> GetProducts(string? cursor, int limit = 20)
        {
            // Simulate database query
            var allProducts = Enumerable.Range(1, 100)
                .Select(i => new Product(
                    Id: i.ToString(),
                    Name: $"Product {i}",
                    CreatedAt: DateTime.UtcNow.AddDays(-i),
                    Price: i * 10.99m
                ))
                .OrderByDescending(p => p.CreatedAt)
                .ToList();

            // Find starting point (cursor)
            var query = allProducts.AsQueryable();
            if (!string.IsNullOrEmpty(cursor))
            {
                var decodedCursor = DecodeCursor(cursor);
                query = query.Where(p => p.CreatedAt < decodedCursor ||
                                        (p.CreatedAt == decodedCursor && p.Id.CompareTo(decodedCursor) < 0));
            }

            var items = query.Take(limit + 1).ToList();
            var hasMore = items.Count > limit;
            if (hasMore) items = items.Take(limit).ToList();

            var nextCursor = hasMore ? EncodeCursor(items.Last()) : null;

            return new CursorPagedResult<Product>(items, nextCursor, hasMore, allProducts.Count);
        }

        private DateTime DecodeCursor(string cursor)
        {
            // Trong thực tế: decode base64 JSON { "createdAt": "...", "id": "..." }
            return DateTime.UtcNow;
        }

        private string EncodeCursor(Product item)
        {
            // Encode { createdAt, id } as base64
            return Convert.ToBase64String(System.Text.Encoding.UTF8.GetBytes(
                $"{{\"createdAt\":\"{item.CreatedAt:O}\",\"id\":\"{item.Id}\"}}"));
        }
    }

