    // ============================================================================
    // SIGNALR HUB — CHAT APPLICATION
    // ============================================================================
    public class ChatHub : Hub
    {
        // Lưu trữ user → connection IDs (multi-device support)
        private static readonly ConcurrentDictionary<string, HashSet<string>> _userConnections = new();

        // Lưu trữ connection ID → user info
        private static readonly ConcurrentDictionary<string, UserInfo> _connectionUsers = new();

        public record UserInfo(int UserId, string Username, string? CurrentRoom);

        // ===== CLIENT INVOKES THESE METHODS =====

        // Client gọi: await hub.InvokeAsync("JoinRoom", roomId, username)
        public async Task JoinRoom(string roomId, string username)
        {
            var userId = GetUserId();
            var connectionId = Context.ConnectionId;

            // Add to SignalR group
            await Groups.AddToGroupAsync(connectionId, roomId);

            // Track connection
            _userConnections.AddOrUpdate(
                userId,
                _ => new HashSet<string> { connectionId },
                (_, set) => { set.Add(connectionId); return set; });

            _connectionUsers[connectionId] = new UserInfo(int.Parse(userId), username, roomId);

            // Notify room members
            await Clients.Group(roomId).SendAsync("UserJoined", new
            {
                UserId = userId,
                Username = username,
                JoinedAt = DateTime.UtcNow
            });

            // Send room history to joining user
            var history = await GetRoomHistoryAsync(roomId);
            await Clients.Caller.SendAsync("RoomHistory", history);

            Console.WriteLine($"[Chat] {username} joined room {roomId} (Connection: {connectionId})");
        }

        // Client gọi: await hub.InvokeAsync("SendMessage", roomId, message)
        public async Task SendMessage(string roomId, string message)
        {
            var connectionId = Context.ConnectionId;
            if (!_connectionUsers.TryGetValue(connectionId, out var userInfo) || userInfo.CurrentRoom != roomId)
                return;

            var chatMessage = new ChatMessage
            {
                Id = Guid.NewGuid().ToString(),
                UserId = userInfo.UserId,
                Username = userInfo.Username,
                RoomId = roomId,
                Content = message,
                SentAt = DateTime.UtcNow
            };

            // Save to database/cache
            await SaveMessageAsync(chatMessage);

            // Broadcast to room group
            await Clients.Group(roomId).SendAsync("ReceiveMessage", chatMessage);

            Console.WriteLine($"[Chat] {userInfo.Username} in {roomId}: {message}");
        }

        // Client gọi: await hub.InvokeAsync("LeaveRoom", roomId)
        public async Task LeaveRoom(string roomId)
        {
            var connectionId = Context.ConnectionId;
            if (!_connectionUsers.TryGetValue(connectionId, out var userInfo))
                return;

            await Groups.RemoveFromGroupAsync(connectionId, roomId);

            // Update tracking
            _connectionUsers[connectionId] = userInfo with { CurrentRoom = null };

            // Notify room
            await Clients.Group(roomId).SendAsync("UserLeft", new
            {
                UserId = userInfo.UserId,
                Username = userInfo.Username,
                LeftAt = DateTime.UtcNow
            });

            Console.WriteLine($"[Chat] {userInfo.Username} left room {roomId}");
        }

        // Client gọi: await hub.InvokeAsync("SendPrivateMessage", targetUserId, message)
        public async Task SendPrivateMessage(string targetUserId, string message)
        {
            var senderInfo = _connectionUsers[Context.ConnectionId];
            var privateMessage = new
            {
                Id = Guid.NewGuid().ToString(),
                FromUserId = senderInfo.UserId,
                FromUsername = senderInfo.Username,
                ToUserId = targetUserId,
                Content = message,
                SentAt = DateTime.UtcNow
            };

            // Gửi đến tất cả connections của target user (multi-device)
            if (_userConnections.TryGetValue(targetUserId, out var connections))
            {
                foreach (var connId in connections)
                {
                    await Clients.Client(connId).SendAsync("ReceivePrivateMessage", privateMessage);
                }
            }

            // Gửi lại cho sender (để hiển thị)
            await Clients.Caller.SendAsync("ReceivePrivateMessage", privateMessage);
        }

