        // ===== FIXED TICK RATE GAME LOOP =====
        private async Task StartGameLoop()
        {
            Console.WriteLine($"[Server] Starting game loop at {TickRate} ticks/second");

            var tickIntervalMs = 1000 / TickRate;
            var nextTickTime = DateTime.UtcNow;

            while (!_cts.Token.IsCancellationRequested)
            {
                var tickStart = DateTime.UtcNow;

                // 1. Process all pending messages from clients
                ProcessPendingMessages();

                // 2. Update game state (physics, AI, etc)
                UpdateGameState();

                // 3. Broadcast state to all connected clients
                BroadcastState();

                // 4. Cleanup disconnected players
                CleanupDisconnectedPlayers();

                var elapsed = (DateTime.UtcNow - tickStart).TotalMilliseconds;
                var sleepTime = tickIntervalMs - elapsed;

                if (sleepTime > 0)
                    await Task.Delay((int)sleepTime);

                // Log FPS tracking
                if (tickStart.Second % 5 == 0)
                    Console.WriteLine($"[Server] Tick completed in {elapsed:F2}ms");
            }
        }

        // ===== MESSAGE PROCESSING =====
        private ConcurrentQueue<PlayerMessage> _messageQueue = new();

        private void ProcessPendingMessages()
        {
            while (_messageQueue.TryDequeue(out var message))
            {
                if (!_rooms.TryGetValue(message.RoomId, out var room))
                    continue;

                switch (message.Type)
                {
                    case MessageType.PlayerInput:
                        room.HandlePlayerInput(message.PlayerId, message.Data);
                        break;

                    case MessageType.Chat:
                        room.HandleChat(message.PlayerId, message.Data);
                        break;

                    case MessageType.PlayerReady:
                        room.HandlePlayerReady(message.PlayerId);
                        break;
                }
            }
        }

        // ===== GAME STATE UPDATE =====
        private void UpdateGameState()
        {
            foreach (var room in _rooms.Values)
            {
                if (room.State != RoomState.Playing) continue;

                // Physics simulation
                room.UpdatePhysics(1.0f / TickRate);

                // Collision detection
                room.CheckCollisions();

                // Game logic (score, win condition, etc)
                room.UpdateGameLogic();
            }
        }

        // ===== STATE BROADCAST =====
        private void BroadcastState()
        {
            foreach (var room in _rooms.Values)
